interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function expandRange(start: number, end: number, step: number = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — each part may itself be a range, step, or number
  if (expr.includes(',')) {
    const seen = new Set<number>();
    for (const part of expr.split(',')) {
      const trimmed = part.trim();
      if (!trimmed) throw new Error(`Empty token in list for field "${field}": "${expr}"`);
      for (const v of parseField(trimmed, field)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step expression: "*/n" or "a-b/n" or "a/n"
  if (expr.includes('/')) {
    const slashIndex = expr.lastIndexOf('/');
    const left = expr.slice(0, slashIndex);
    const right = expr.slice(slashIndex + 1);
    const step = parseInt(right, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step "${right}" in "${expr}" for field "${field}"`);
    }
    let start: number;
    let end: number;
    if (left === '*') {
      start = min;
      end = max;
    } else if (left.includes('-')) {
      const [s, e] = left.split('-').map(n => parseInt(n, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range "${left}" in "${expr}" for field "${field}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(left, 10);
      if (isNaN(start)) throw new Error(`Invalid start "${left}" in "${expr}" for field "${field}"`);
      end = max;
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}] for field "${field}"`);
    }
    return expandRange(start, end, step);
  }

  // Wildcard
  if (expr === '*') {
    return expandRange(min, max);
  }

  // Range: "a-b"
  if (expr.includes('-')) {
    const parts = expr.split('-');
    if (parts.length !== 2) throw new Error(`Invalid range "${expr}" for field "${field}"`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Non-numeric range "${expr}" for field "${field}"`);
    if (start > end) throw new Error(`Range start ${start} exceeds end ${end} for field "${field}"`);
    if (start < min || end > max) throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}] for field "${field}"`);
    return expandRange(start, end);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num) || String(num) !== expr.trim()) {
    throw new Error(`Invalid value "${expr}" for field "${field}"`);
  }
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of bounds [${min}-${max}] for field "${field}"`);
  }
  return [num];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== 'string') throw new Error('Cron expression must be a string');

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
