  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num) || String(num) !== expr.trim()) {
    throw new Error(`Invalid value "${expr}" for field "${field}"`);
  }
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of bounds [${min}-${max}] for field "${field}"`);
  }
  return [num];
}

